"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["20736"],{76343(e){e.exports=JSON.parse('{"tag":{"label":"Go SDK","permalink":"/tags/go-sdk","allTagsPath":"/tags","count":29,"items":[{"id":"develop/go/asynchronous-activity-completion","title":"Asynchronous Activity completion - Go SDK","description":"Asynchronous Activity Completion lets the Activity Function return without finishing Activity Execution. Use Task Tokens and Temporal Client to complete the Activity externally.","permalink":"/develop/go/asynchronous-activity-completion"},{"id":"develop/go/benign-exceptions","title":"Benign exceptions - Go SDK","description":"Mark expected or non-severe Activity errors as benign to reduce noise in logs, metrics, and OpenTelemetry traces.","permalink":"/develop/go/benign-exceptions"},{"id":"develop/go/child-workflows","title":"Child Workflows - Go SDK","description":"Use the Go SDK to start a Child Workflow Execution and set a Parent Close Policy, including details on Workflow Options and future management.","permalink":"/develop/go/child-workflows"},{"id":"develop/go/context-propagation","title":"Context Propagation - Go SDK","description":"How to propagate custom key-value data across Workflow, Activity, and Child Workflow boundaries using the Temporal Go SDK.","permalink":"/develop/go/context-propagation"},{"id":"develop/go/continue-as-new","title":"Continue-As-New - Go SDK","description":"Use Temporal\'s Continue-As-New in Go to manage large Event Histories by atomically creating new Workflow Executions with the same Workflow Id and fresh parameters.","permalink":"/develop/go/continue-as-new"},{"id":"develop/go/converters-and-encryption","title":"Converters and encryption - Go SDK","description":"Use a custom Payload Codec and Payload Converter in Go. Create custom PayloadCodec implementations, set Data Converters, and apply transformations effectively using the Temporal SDK.","permalink":"/develop/go/converters-and-encryption"},{"id":"develop/go/core-application","title":"Core application - Go SDK","description":"The Foundations section of the Temporal Developer\'s guide introduces essential concepts for building and running a Temporal Application, outlining steps to start Workflow and Activity Execution, running development Workers, and installing the Temporal CLI.","permalink":"/develop/go/core-application"},{"id":"develop/go/debugging","title":"Debugging - Go SDK","description":"Use debugger tools and set TEMPORAL_DEBUG to true for debugging Workflow Definitions with the Temporal Go SDK, and debug production Workflows via Web UI, CLI, or tracing.","permalink":"/develop/go/debugging"},{"id":"develop/go/timers","title":"Durable Timers - Go SDK","description":"Set Durable Timers in a Workflow using the sleep() or NewTimer() functions in Go with Temporal. Timers persist through Worker and Temporal Service downtime.","permalink":"/develop/go/timers"},{"id":"production-deployment/self-hosted-guide/embedded-server","title":"Embedding Temporal server as a Go library","description":"Run Temporal server as an embedded Go library for testing and development. Learn how to use temporal.NewServer() to run Temporal server in-process.","permalink":"/self-hosted-guide/embedded-server"},{"id":"develop/go/enriching-ui","title":"Enriching the user interface - Go SDK","description":"Add contextual information to workflows and events in the Temporal UI using the Go SDK.","permalink":"/develop/go/enriching-ui"},{"id":"develop/go/failure-detection","title":"Failure detection - Go SDK","description":"Handle errors, configure Workflow timeouts, set Retry Policies, and manage Activity timeouts and Heartbeats using Temporal\'s Go SDK.","permalink":"/develop/go/failure-detection"},{"id":"develop/go/index","title":"Go SDK developer guide","description":"Explore the Temporal Go SDK feature guides to seamlessly develop and manage Temporal Applications with core components, Temporal Client connections, testing, debugging, versioning, and more.","permalink":"/develop/go/"},{"id":"develop/go/cancellation","title":"Interrupt a Workflow - Go SDK","description":"Handle Cancellations in Temporal Workflows and Activities, set Activity Heartbeat Timeouts, and send Cancellation requests from a Temporal Client in Go.","permalink":"/develop/go/cancellation"},{"id":"develop/go/namespaces","title":"Namespaces - Go SDK","description":"Register and manage Namespaces in Temporal using CLI or SDK APIs. Isolate Workflow Executions, match development lifecycles, and secure Namespace workflows.","permalink":"/develop/go/namespaces"},{"id":"develop/go/observability","title":"Observability - Go SDK","description":"Monitor your Temporal Application state using Metrics, Tracing, Logging, and Visibility features. Emit metrics, configure tracing, customize logging, and use Search Attributes with the Temporal Go SDK for enhanced Workflow Execution insights.","permalink":"/develop/go/observability"},{"id":"develop/go/schedules","title":"Schedules - Go SDK","description":"Schedule Workflows, start them with delays or as Temporal Cron Jobs using the Go SDK. Master scheduling, backfilling, pausing, deleting, and updating Workflows.","permalink":"/develop/go/schedules"},{"id":"develop/go/selectors","title":"Selectors - Go SDK","description":"Use Temporal\u2019s Go SDK Selectors with Futures, Timers, and Channels. Ensure deterministic Workflow execution and handle multiple parallel tasks efficiently.","permalink":"/develop/go/selectors"},{"id":"develop/go/set-up-your-local-go","title":"Set up your local with the Go SDK","description":"Configure your local development environment to get started developing with Temporal","permalink":"/develop/go/set-up-your-local-go"},{"id":"develop/go/side-effects","title":"Side Effects - Go SDK","description":"Side Effects in Workflows execute non-deterministic code, storing results in the Workflow Event History to maintain determinism. Use Go\'s SideEffect function for integration.","permalink":"/develop/go/side-effects"},{"id":"develop/go/standalone-activities","title":"Standalone Activities - Go SDK","description":"Execute Activities independently without a Workflow using the Temporal Go SDK.","permalink":"/develop/go/standalone-activities"},{"id":"develop/go/temporal-client","title":"Temporal Client - Go SDK","description":"Connect to Temporal Service or Cloud, start Workflow Executions, manage Workflow options, and retrieve Workflow results using the Go SDK. Follow detailed steps and code examples to effectively use Temporal\u2019s capabilities.","permalink":"/develop/go/temporal-client"},{"id":"develop/go/go-sdk-multithreading","title":"Temporal Go SDK multithreading","description":"The Temporal Go SDK ensures deterministic multithreading in Workflows using workflow.Go(), avoiding race conditions and eliminating the need for mutexes.","permalink":"/develop/go/go-sdk-multithreading"},{"id":"develop/go/nexus","title":"Temporal Nexus - Go SDK feature guide","description":"Use Temporal Nexus within the Go SDK to connect durable executions within and across Namespaces using a Nexus Endpoint, a Nexus Service contract, and Nexus Operations.","permalink":"/develop/go/nexus"},{"id":"develop/go/testing-suite","title":"Testing - Go SDK","description":"The Testing section of the Temporal Application development guide details frameworks for Workflow and integration testing. Create end-to-end, integration, unit tests, and more for Workflows and Activities. Each test runs in an isolated environment, ensuring accurate and reliable testing. Discover how to mock and override Activities, test","permalink":"/develop/go/testing-suite"},{"id":"develop/go/versioning","title":"Versioning - Go SDK","description":"Temporal\'s Go SDK ensures Workflow determinism through Patching APIs and Worker Versioning. Update Workflow code without causing non-deterministic issues, understand versioning best practices, and use dynamic configuration parameters for seamless updating of long-running Workflows.","permalink":"/develop/go/versioning"},{"id":"develop/go/sessions","title":"Worker Sessions - Go SDK","description":"Enable Worker Sessions, change concurrent Sessions, and create Session Workers using the Go SDK for precise Task Routing, ensuring efficient Activity Tasks execution.","permalink":"/develop/go/sessions"},{"id":"develop/go/worker-versioning-legacy","title":"Worker Versioning (Legacy) - Go SDK","description":"Learn the Go SDK\'s outdated Worker Versioning APIs.","permalink":"/develop/go/worker-versioning-legacy"},{"id":"develop/go/message-passing","title":"Workflow message passing - Go SDK","description":"Develop with Queries, Signals, and Updates with the Temporal Go SDK.","permalink":"/develop/go/message-passing"}],"unlisted":false}}')}}]);